use std::path::Path;

use codex_repo_index::RepoMap;

use crate::build_context_packet;
use crate::metrics::ContextMetrics;
use crate::metrics::EvalDiagnostics;
use crate::metrics::EvalLabels;
use crate::metrics::Metrics;
use crate::pipeline::BuildPacketOptions;
use crate::run_memory::RunMemory;

#[derive(Debug, Clone, serde::Deserialize, serde::Serialize)]
#[serde(deny_unknown_fields)]
pub struct EvalTaskFixture {
    pub task: String,
    #[serde(alias = "gold_files")]
    pub relevant_files: Vec<String>,
    #[serde(alias = "gold_tests", default)]
    pub relevant_tests: Vec<String>,
    #[serde(default)]
    pub bridge_files: Vec<String>,
    #[serde(default)]
    pub danger_zones: Vec<String>,
    #[serde(default)]
    pub repo_map: Option<RepoMap>,
}

#[derive(Debug, Clone, PartialEq, serde::Serialize)]
#[serde(deny_unknown_fields)]
pub struct EvalTaskResult {
    pub task: String,
    pub metrics: ContextMetrics,
    pub diagnostics: EvalDiagnostics,
}

#[derive(Debug, Clone, PartialEq, serde::Serialize)]
#[serde(deny_unknown_fields)]
pub struct EvalReport {
    pub task_count: usize,
    pub avg_recall: f64,
    pub avg_waste: f64,
    pub avg_test_accuracy: f64,
    pub avg_token_estimate: u32,
    pub avg_bridge_file_recall: Option<f64>,
    pub tasks: Vec<EvalTaskResult>,
}

pub fn load_eval_fixtures(path: &Path) -> anyhow::Result<Vec<EvalTaskFixture>> {
    let bytes = std::fs::read(path)?;
    let fixtures: Vec<EvalTaskFixture> = serde_json::from_slice(&bytes)?;
    Ok(fixtures)
}

pub fn run_eval(
    fixtures: &[EvalTaskFixture],
    map: &RepoMap,
    options: BuildPacketOptions,
) -> EvalReport {
    let mut tasks = Vec::new();
    let mut recall_sum = 0.0;
    let mut waste_sum = 0.0;
    let mut test_sum = 0.0;
    let mut token_sum = 0u32;
    let mut bridge_sum = 0.0;
    let mut bridge_count = 0usize;

    for fixture in fixtures {
        let eval_map = fixture.repo_map.as_ref().unwrap_or(map);
        let packet = build_context_packet(
            &fixture.task,
            eval_map,
            &RunMemory::default(),
            options.clone(),
        );
        let labels = EvalLabels {
            relevant_files: fixture.relevant_files.clone(),
            relevant_tests: fixture.relevant_tests.clone(),
            bridge_files: fixture.bridge_files.clone(),
        };
        let metrics = Metrics::evaluate(&packet, &labels);
        let diagnostics = Metrics::diagnose(&packet, &labels);
        recall_sum += metrics.relevant_file_recall;
        waste_sum += metrics.context_waste;
        test_sum += metrics.test_selection_accuracy;
        token_sum += metrics.token_estimate;
        if let Some(bridge) = metrics.bridge_file_recall {
            bridge_sum += bridge;
            bridge_count += 1;
        }
        tasks.push(EvalTaskResult {
            task: fixture.task.clone(),
            metrics,
            diagnostics,
        });
    }

    let count = fixtures.len().max(1);
    EvalReport {
        task_count: fixtures.len(),
        avg_recall: recall_sum / count as f64,
        avg_waste: waste_sum / count as f64,
        avg_test_accuracy: test_sum / count as f64,
        avg_token_estimate: token_sum / count as u32,
        avg_bridge_file_recall: if bridge_count == 0 {
            None
        } else {
            Some(bridge_sum / bridge_count as f64)
        },
        tasks,
    }
}

pub fn render_eval_summary(report: &EvalReport) -> String {
    let bridge_line = report
        .avg_bridge_file_recall
        .map(|bridge| format!("\navg_bridge_file_recall: {bridge:.2}"))
        .unwrap_or_default();
    format!(
        "task_count: {}\navg_recall: {:.2}\navg_waste: {:.2}\navg_test_accuracy: {:.2}\navg_token_estimate: {}{bridge_line}",
        report.task_count,
        report.avg_recall,
        report.avg_waste,
        report.avg_test_accuracy,
        report.avg_token_estimate,
    )
}

pub fn render_eval_human(report: &EvalReport) -> String {
    let mut lines = vec![render_eval_summary(report), String::new()];
    for task in &report.tasks {
        lines.push(format!("Task: {}", task.task));
        lines.push(format!(
            "  Recall: {:.2}",
            task.metrics.relevant_file_recall
        ));
        lines.push(format!("  Waste: {:.2}", task.metrics.context_waste));
        lines.push(format!(
            "  Tests: {:.2}",
            task.metrics.test_selection_accuracy
        ));
        lines.push(format!("  Tokens: {}", task.metrics.token_estimate));
        if let Some(bridge) = task.metrics.bridge_file_recall {
            lines.push(format!("  Bridge recall: {bridge:.2}"));
        }
        if !task.diagnostics.missed_gold_files.is_empty() {
            lines.push("  Missed gold files:".to_string());
            for path in &task.diagnostics.missed_gold_files {
                lines.push(format!("    - {path}"));
            }
        }
        if !task.diagnostics.missed_bridge_files.is_empty() {
            lines.push("  Missed bridge files:".to_string());
            for path in &task.diagnostics.missed_bridge_files {
                lines.push(format!("    - {path}"));
            }
        }
        if !task.diagnostics.extra_included_files.is_empty() {
            lines.push("  Extra included files:".to_string());
            for path in &task.diagnostics.extra_included_files {
                lines.push(format!("    - {path}"));
            }
        }
        if !task.diagnostics.missed_gold_tests.is_empty() {
            lines.push("  Missed gold tests:".to_string());
            for path in &task.diagnostics.missed_gold_tests {
                lines.push(format!("    - {path}"));
            }
        }
        if !task.diagnostics.extra_selected_tests.is_empty() {
            lines.push("  Extra selected tests:".to_string());
            for path in &task.diagnostics.extra_selected_tests {
                lines.push(format!("    - {path}"));
            }
        }
        lines.push(String::new());
    }
    lines.join("\n")
}

//! Offline artifact scoring for vanilla vs harness-context agent runs.
//!
//! `agent-eval score` reads fixture labels and per-arm `record.json` files only.
//! It does not start Codex, mutate a repo, or use the network.

use std::path::Path;
use std::path::PathBuf;

use anyhow::Context;
use anyhow::Result;
use anyhow::bail;
use clap::Parser;
use codex_context_harness::AgentArm;
use codex_context_harness::AgentEvalReport;
use codex_context_harness::AgentRunRecord;
use codex_context_harness::build_report;
use codex_context_harness::compare_task;
use codex_context_harness::load_agent_eval_tasks;
use codex_context_harness::render_agent_eval_human;

#[derive(Debug, Parser)]
pub struct ContextAgentEvalCli {
    #[command(subcommand)]
    pub subcommand: ContextAgentEvalSubcommand,
}

#[derive(Debug, clap::Subcommand)]
pub enum ContextAgentEvalSubcommand {
    /// Score vanilla vs harness run records under an artifacts directory.
    Score(ContextAgentEvalScoreCommand),
}

#[derive(Debug, Parser)]
pub struct ContextAgentEvalScoreCommand {
    /// Task fixture (same tasks for both arms).
    #[arg(long)]
    pub fixture: PathBuf,
    /// Directory with `{task_id}/vanilla/record.json` and treatment arm `record.json`.
    #[arg(long)]
    pub artifacts_dir: PathBuf,
    /// Treatment arm: `harness` (manual prefix) or `repo_intelligence` (session injection).
    #[arg(long)]
    pub treatment_arm: Option<String>,
    #[arg(long)]
    pub human: bool,
    #[arg(long)]
    pub json_out: Option<PathBuf>,
}

pub async fn run_context_agent_eval(command: ContextAgentEvalCli) -> Result<()> {
    match command.subcommand {
        ContextAgentEvalSubcommand::Score(cmd) => run_agent_eval_score(cmd).await,
    }
}

async fn run_agent_eval_score(cmd: ContextAgentEvalScoreCommand) -> Result<()> {
    let tasks = load_agent_eval_tasks(&cmd.fixture)?;
    let task_ids: Vec<String> = tasks.iter().map(|t| t.id.clone()).collect();
    let treatment_arm = resolve_treatment_arm(&cmd, &task_ids)?;
    validate_artifacts_layout(&cmd.artifacts_dir, &task_ids, treatment_arm)?;
    let mut comparisons = Vec::new();
    for task in &tasks {
        let vanilla = load_run_record(&cmd.artifacts_dir, &task.id, AgentArm::Vanilla)?;
        let treatment = load_run_record(&cmd.artifacts_dir, &task.id, treatment_arm)?;
        comparisons.push(compare_task(task, &vanilla, &treatment));
    }
    let report = build_report(comparisons);
    emit_report(&cmd, &report)
}

fn resolve_treatment_arm(
    cmd: &ContextAgentEvalScoreCommand,
    task_ids: &[String],
) -> Result<AgentArm> {
    if let Some(ref name) = cmd.treatment_arm {
        return parse_treatment_arm(name);
    }
    detect_treatment_arm(&cmd.artifacts_dir, task_ids)
}

fn parse_treatment_arm(name: &str) -> Result<AgentArm> {
    match name {
        "harness" => Ok(AgentArm::Harness),
        "repo_intelligence" => Ok(AgentArm::RepoIntelligence),
        other => {
            bail!("unknown treatment arm {other:?}; expected \"harness\" or \"repo_intelligence\"")
        }
    }
}

fn detect_treatment_arm(artifacts_dir: &Path, task_ids: &[String]) -> Result<AgentArm> {
    let Some(task_id) = task_ids.first() else {
        bail!("fixture has no tasks");
    };
    let repo_intel = artifacts_dir
        .join(task_id)
        .join(AgentArm::RepoIntelligence.artifact_dir())
        .join("record.json");
    if repo_intel.is_file() {
        return Ok(AgentArm::RepoIntelligence);
    }
    let harness = artifacts_dir
        .join(task_id)
        .join(AgentArm::Harness.artifact_dir())
        .join("record.json");
    if harness.is_file() {
        return Ok(AgentArm::Harness);
    }
    bail!(
        "could not detect treatment arm under {}; expected {} or {}",
        artifacts_dir.display(),
        AgentArm::RepoIntelligence.artifact_dir(),
        AgentArm::Harness.artifact_dir()
    );
}

fn load_run_record(base: &Path, task_id: &str, arm: AgentArm) -> Result<AgentRunRecord> {
    let path = base
        .join(task_id)
        .join(arm.artifact_dir())
        .join("record.json");
    let bytes = std::fs::read(&path).with_context(|| format!("read {}", path.display()))?;
    serde_json::from_slice(&bytes).with_context(|| format!("parse {}", path.display()))
}

fn emit_report(cmd: &ContextAgentEvalScoreCommand, report: &AgentEvalReport) -> Result<()> {
    let payload = if cmd.human {
        render_agent_eval_human(report)
    } else {
        serde_json::to_string_pretty(report)?
    };
    if let Some(path) = &cmd.json_out {
        std::fs::write(path, &payload).with_context(|| format!("write {}", path.display()))?;
    } else {
        println!("{payload}");
    }
    Ok(())
}

pub fn validate_artifacts_layout(
    artifacts_dir: &Path,
    task_ids: &[String],
    treatment_arm: AgentArm,
) -> Result<()> {
    for task_id in task_ids {
        for arm in [AgentArm::Vanilla, treatment_arm] {
            let path = artifacts_dir
                .join(task_id)
                .join(arm.artifact_dir())
                .join("record.json");
            if !path.is_file() {
                bail!("missing artifact: {}", path.display());
            }
        }
    }
    Ok(())
}

use crate::packet::ContextPacket;
use crate::packet::RenderLevel;

#[derive(Debug, Clone, Default)]
pub struct EvalLabels {
    pub relevant_files: Vec<String>,
    pub relevant_tests: Vec<String>,
    pub bridge_files: Vec<String>,
}

#[derive(Debug, Clone, PartialEq, serde::Serialize)]
#[serde(deny_unknown_fields)]
pub struct ContextMetrics {
    pub relevant_file_recall: f64,
    pub context_waste: f64,
    pub test_selection_accuracy: f64,
    pub token_estimate: u32,
    pub bridge_file_recall: Option<f64>,
    pub dropped_count: usize,
    pub budget_exhausted_count: usize,
    pub low_confidence_count: usize,
}

#[derive(Debug, Clone, PartialEq, Eq, serde::Serialize)]
#[serde(deny_unknown_fields)]
pub struct EvalDiagnostics {
    pub missed_gold_files: Vec<String>,
    pub extra_included_files: Vec<String>,
    pub missed_gold_tests: Vec<String>,
    pub extra_selected_tests: Vec<String>,
    pub missed_bridge_files: Vec<String>,
    pub extra_bridge_rendered: Vec<String>,
}

pub struct Metrics;

impl Metrics {
    pub fn evaluate(packet: &ContextPacket, labels: &EvalLabels) -> ContextMetrics {
        let included_paths: Vec<String> = packet
            .included_paths()
            .into_iter()
            .map(str::to_string)
            .collect();

        let relevant_file_recall = recall(&included_paths, &labels.relevant_files);
        let context_waste = waste(&included_paths, &labels.relevant_files);

        let selected: Vec<String> = packet
            .selected_tests
            .iter()
            .map(|t| t.path.clone())
            .collect();
        let test_selection_accuracy = recall(&selected, &labels.relevant_tests);

        let bridge_file_recall = if labels.bridge_files.is_empty() {
            None
        } else {
            Some(recall(&included_paths, &labels.bridge_files))
        };

        ContextMetrics {
            relevant_file_recall,
            context_waste,
            test_selection_accuracy,
            token_estimate: packet.token_budget.used_estimate,
            bridge_file_recall,
            dropped_count: packet.decision_log.dropped.len(),
            budget_exhausted_count: packet.decision_log.budget_exhausted.len(),
            low_confidence_count: packet.decision_log.low_confidence.len(),
        }
    }

    pub fn diagnose(packet: &ContextPacket, labels: &EvalLabels) -> EvalDiagnostics {
        let included_paths: Vec<String> = packet
            .included_paths()
            .into_iter()
            .map(str::to_string)
            .collect();
        let selected: Vec<String> = packet
            .selected_tests
            .iter()
            .map(|t| t.path.clone())
            .collect();

        let bridge_rendered: Vec<String> = packet
            .items
            .iter()
            .filter(|item| {
                item.path
                    .as_ref()
                    .is_some_and(|path| labels.bridge_files.iter().any(|bridge| bridge == path))
                    && item.render_level != RenderLevel::HiddenDebugOnly
            })
            .filter_map(|item| item.path.clone())
            .collect();

        EvalDiagnostics {
            missed_gold_files: labels
                .relevant_files
                .iter()
                .filter(|path| !included_paths.iter().any(|s| s == *path))
                .cloned()
                .collect(),
            extra_included_files: included_paths
                .iter()
                .filter(|path| !labels.relevant_files.iter().any(|g| g == *path))
                .cloned()
                .collect(),
            missed_gold_tests: labels
                .relevant_tests
                .iter()
                .filter(|path| !selected.iter().any(|s| s == *path))
                .cloned()
                .collect(),
            extra_selected_tests: selected
                .iter()
                .filter(|path| !labels.relevant_tests.iter().any(|g| g == *path))
                .cloned()
                .collect(),
            missed_bridge_files: labels
                .bridge_files
                .iter()
                .filter(|path| !included_paths.iter().any(|s| s == *path))
                .cloned()
                .collect(),
            extra_bridge_rendered: bridge_rendered
                .iter()
                .filter(|path| !labels.bridge_files.iter().any(|g| g == *path))
                .cloned()
                .collect(),
        }
    }
}

fn recall(selected: &[String], gold: &[String]) -> f64 {
    if gold.is_empty() {
        return 1.0;
    }
    let hits = gold
        .iter()
        .filter(|path| selected.iter().any(|s| s == *path))
        .count();
    hits as f64 / gold.len() as f64
}

fn waste(selected: &[String], gold: &[String]) -> f64 {
    if selected.is_empty() {
        return 0.0;
    }
    let irrelevant = selected
        .iter()
        .filter(|path| !gold.iter().any(|g| g == *path))
        .count();
    irrelevant as f64 / selected.len() as f64
}

//! Scoring for vanilla vs harness-context agent runs on the same tasks.
//!
//! Consumes per-run artifacts (git diff, test exit code, optional exec JSONL) and
//! fixture gold labels. Does not invoke models.

use std::collections::BTreeMap;
use std::collections::BTreeSet;
use std::path::Path;

use serde::Deserialize;
use serde::Serialize;

use crate::eval::EvalTaskFixture;

/// Task fixture for agent A/B evals (extends packet-eval labels with run metadata).
#[derive(Debug, Clone, Deserialize, Serialize)]
#[serde(deny_unknown_fields)]
pub struct AgentEvalTask {
    #[serde(default)]
    pub id: String,
    pub task: String,
    #[serde(alias = "gold_files")]
    pub relevant_files: Vec<String>,
    #[serde(alias = "gold_tests", default)]
    pub relevant_tests: Vec<String>,
    #[serde(default)]
    pub danger_zones: Vec<String>,
    /// Shell command that must exit 0 for `tests_passed` (e.g. narrow pytest).
    #[serde(default)]
    pub verify_command: Option<String>,
    /// Paths that connect areas (CLI ↔ core ↔ harness); scored as `bridge_files_touched`.
    #[serde(default)]
    pub bridge_files: Vec<String>,
    /// `calculator` copies the Python E2E fixture; `codex_rs` runs in the codex-rs tree.
    #[serde(default)]
    pub workdir: AgentEvalWorkdir,
    /// Coarse-grained category for grouping the report. None tasks render under
    /// a final "uncategorized" group.
    #[serde(default)]
    pub category: Option<TaskCategory>,
}

/// What aspect of repo intelligence a task is meant to exercise. Used purely
/// for report grouping — scoring is unchanged across categories.
#[derive(Debug, Clone, Copy, PartialEq, Eq, PartialOrd, Ord, Serialize, Deserialize)]
#[serde(rename_all = "snake_case")]
pub enum TaskCategory {
    /// Multiple files share the same keyword; RI should route to the right
    /// one before the first edit.
    FileRouting,
    /// Task names an owner concept; RI should also surface the bridge file
    /// the agent has to touch to wire it.
    BridgeWiring,
    /// Task names a behavior to verify; RI should point at the matching test
    /// file rather than a same-named file in src/.
    TestTargeting,
    /// Task asks to follow a convention that exists in one specific file
    /// (e.g. a feature-flag entry); RI should surface that file.
    LocalConvention,
    /// Task implicitly requires edits in two or more crates; RI should
    /// surface both owner and dependent.
    CrossModuleOwnership,
}

impl TaskCategory {
    pub fn slug(self) -> &'static str {
        match self {
            Self::FileRouting => "file_routing",
            Self::BridgeWiring => "bridge_wiring",
            Self::TestTargeting => "test_targeting",
            Self::LocalConvention => "local_convention",
            Self::CrossModuleOwnership => "cross_module_ownership",
        }
    }
}

/// Recorded outcome of one agent run (vanilla or harness-context).
#[derive(Debug, Clone, PartialEq, Serialize, Deserialize)]
#[serde(deny_unknown_fields)]
pub struct AgentRunRecord {
    pub arm: AgentArm,
    pub task_id: String,
    pub changed_files: Vec<String>,
    pub tests_passed: bool,
    pub turn_count: Option<u32>,
    #[serde(default)]
    pub exec_exit_code: Option<i32>,
    #[serde(default)]
    pub repo_intelligence_enabled: bool,
    #[serde(default)]
    pub harness_context_visible: bool,
    #[serde(default = "default_true")]
    pub run_valid: bool,
    #[serde(default)]
    pub invalid_reason: Option<AgentRunInvalidReason>,
    /// Sum of `turn.completed.usage.input_tokens` across all turns. `None` if
    /// no `turn.completed` events were parsed (e.g. missing/empty events.jsonl).
    #[serde(default)]
    pub tokens_input: Option<u64>,
    #[serde(default)]
    pub tokens_output: Option<u64>,
    #[serde(default)]
    pub tokens_total: Option<u64>,
    /// Wall-clock duration of the `codex exec` invocation in milliseconds.
    /// `None` for pre-duration records (`serde(default)`). The point of
    /// recording this is that *time* is part of the RI claim — if RI adds
    /// prompt tokens but avoids file-search turns, it can still be a net win
    /// on the metric users actually feel.
    #[serde(default)]
    pub duration_ms: Option<u64>,
    /// Count of `item.completed` events of any item type. A coarse proxy
    /// for "how many tool calls did the model make this turn".
    #[serde(default)]
    pub tool_call_count: Option<u32>,
    /// Count of `item.completed` events with `item.type == "command_execution"`.
    /// Direct measure of how many shell commands the agent fired.
    #[serde(default)]
    pub shell_command_count: Option<u32>,
    /// Heuristic count of file-read shell commands (`cat`/`head`/`tail`/
    /// `less`/`more`). Diagnostic — captures "stupid file-finding" but not
    /// loads via codex's structured file-read tool, if any.
    #[serde(default)]
    pub file_read_count: Option<u32>,
    /// Phase-classified shell command counts. See [`classify_shell_phase`]
    /// for the heuristic. Sum of all four phase counts (discover + read +
    /// edit + verify) plus an unrecorded "other" residual equals
    /// `shell_command_count`. None for pre-phase-instrumentation records.
    #[serde(default)]
    pub discover_command_count: Option<u32>,
    #[serde(default)]
    pub edit_command_count: Option<u32>,
    #[serde(default)]
    pub verify_command_count: Option<u32>,
    /// True when this arm ran in a worktree that was not shared with any other
    /// arm or task. For `codex_rs` workdirs that means `--isolated-worktrees`
    /// was set; for `calculator` workdirs the arm always gets a fresh
    /// `mktemp -d` + `git init`, so this is always true.
    #[serde(default)]
    pub worktree_isolated: bool,
    /// Resolved git SHA the arm's worktree started from. `None` for
    /// `calculator` workdirs (no shared base ref) and for non-isolated
    /// `codex_rs` runs.
    #[serde(default)]
    pub base_ref: Option<String>,
    /// Absolute path of the cwd the arm ran in. Recorded so a reviewer can
    /// later distinguish two runs that nominally shared the same checkout
    /// from two runs that were genuinely isolated.
    #[serde(default)]
    pub worktree_path: Option<String>,
}

fn default_true() -> bool {
    true
}

#[derive(Debug, Clone, Copy, PartialEq, Eq, Default, Serialize, Deserialize)]
#[serde(rename_all = "snake_case")]
pub enum AgentEvalWorkdir {
    #[default]
    Calculator,
    CodexRs,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq, Serialize, Deserialize)]
#[serde(rename_all = "snake_case")]
pub enum AgentArm {
    Vanilla,
    Harness,
    RepoIntelligence,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq, Serialize, Deserialize)]
#[serde(rename_all = "snake_case")]
pub enum AgentRunInvalidReason {
    ProviderUsageLimit,
    ProviderAuthError,
    ProviderNetworkError,
    TurnFailed,
    RunnerError,
    MissingEvents,
    UnknownFailure,
}

impl AgentArm {
    pub fn artifact_dir(self) -> &'static str {
        match self {
            Self::Vanilla => "vanilla",
            Self::Harness => "harness",
            Self::RepoIntelligence => "repo_intelligence",
        }
    }

    pub fn display_label(self) -> &'static str {
        self.artifact_dir()
    }
}

/// Per-run scores for one arm.
#[derive(Debug, Clone, PartialEq, Serialize, Deserialize)]
#[serde(deny_unknown_fields)]
pub struct AgentRunScore {
    /// True if any gold (`relevant_files`) path was touched.
    pub correct_file_touched: bool,
    /// Count of distinct paths from (gold ∪ bridge) that were touched.
    pub target_files_hit: usize,
    /// Size of the (gold ∪ bridge) set, i.e. denominator for target_files_hit.
    pub target_files_total: usize,
    pub tests_passed: bool,
    pub turn_count: Option<u32>,
    pub unnecessary_files_changed: Vec<String>,
    pub harness_context_visible: bool,
    pub bridge_files_touched: Vec<String>,
    pub run_valid: bool,
    pub invalid_reason: Option<AgentRunInvalidReason>,
    pub tokens_input: Option<u64>,
    pub tokens_output: Option<u64>,
    pub tokens_total: Option<u64>,
    /// Wall-clock duration in ms (from the script-side bracket around
    /// `codex exec`). Used by the classifier between `turns` and `tokens`.
    pub duration_ms: Option<u64>,
    /// Diagnostic: total `item.completed` events the agent emitted.
    pub tool_call_count: Option<u32>,
